sp_widget.client_script:
function($scope, $location, $timeout, $rootScope) {
    /* widget controller */
    var c = this;

    if (c.data.accountOU === 'JP' ||c.data.accountOU === 'ES') {
        $scope.tabs = ['${Dashboard}', '${History}']
    } else if (c.data.pemission == true) {
        $scope.tabs = ['${Dashboard}', '${History}', '${Maintenance}', '${My Plan}'];
    } else {
        $scope.tabs = ['${Dashboard}', '${History}', '${Maintenance}'];
    }


    // Default tab
    c.active_tab = 'Dashboard';
    identifyPageTracking($scope.data.pageTitle, 'Monitoring', c.data.trackingEnabled, c.data.categoriesTrackingEnabled);


}

sp_widget.css:
#backup-tab-content {
  position: relative;
}

.modal-dialog {
  @media screen and (min-width: 992px) {
    width: 79vw;
    height: 90vh;
  }
}

.panel {
	position: relative;
}

.panel-fullscreen {
	transition: 0.6s;
}

.maximize {
  width: 100%;
  height: 100%;
	position: fixed;
  top: 0;
  left: 0;
  z-index: 99;
  transition: 0.6s;
}

.panel-heading h4 {
	margin-top: 0;
}

.divider {
  margin-top: 24px;
  margin-left: -20px;
  border-bottom: 1px solid #D9D9D9;
  width: calc(100% + 40px);
  height: 0px;
}

.title {
  font-size: 16px;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-normal);
  color: #404040;
  margin-top: 10px;
  margin-bottom: 10px;
}

.margin-top {
  margin-top: 16px;
}

.dropdown-menu > li > a {
  display: block;
  padding: 3px 20px;
  clear: both;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
  line-height: 1.42857;
  color: #ADADAD;
  white-space: nowrap;
}

.dropdown-menu > li > a > i {
  color: #898989;
  margin-right: 5px;
}

.summary-actions {
  position: absolute;
  right: 10px;
  top: 5px;
}

.equipment-info > .type {
  color: #ACA9A9;
  font-size: 12px;
  line-height: 12px;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
}

.equipment-info > .name {
  color: #6C6C6C;
}

.equipment-info > .name> i {
  color: #FFE200;
}

.equipment-info > .name> i:first-child {
  margin-left: 10px;
}

.backup-status {
  padding: 12px 0px;
  color: #8E9B70;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);

}

.backup-status div {
  margin-bottom: 3px;
}

.backup-status i {
  color: #A3D15E;
  margin-right: 3px;
  font-size: 18px;
}

.backup-status i.info {
  color: #FF8600;
}
.backup-status a{
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
}

.restore-status {
  color: #B0D73A;
  padding: 10px 0px;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
}


.restore-status i {
  color: #A3D15E;
  font-size: 18px;
  margin-right: 10px;
}

.tag.success {
  background-color: #9DCD00;
  color: #FFF;
}

.tag.danger {
  background-color: #E90000;
  color: #FFF;
}

.tag-stats > .tag {
  display: inline-block;
  padding: 1px 15px;
  border-radius: 30px;
  font-size: 10px;
  margin-right: 3px;
}

.tag-stats {
  padding: 10px 0px 15px 0px;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
}

.vpn-section {
  padding: 12px 0px;
  font-size: 1.3rem;
  line-height: 1.6;
}

.v7f3de4ecdb199f80b3cd73e1ba961935 .panel-title {
  margin-bottom: 8px;
  font-family: var(--eq-font-family);
  font-weight: var(--eq-font-weight-light);
  font-size: 1.8rem;
}

.dropdown {
  .btn {
    padding: 0 8px !important;
    color: $info;
    font-size: 18px !important;

    &:focus,
    &:hover {
      background: none;
      outline: none;
    }

    &:active {
      box-shadow: none;
    }
  }
}

.dropdown-menu {
  padding: 8px 0;
  min-width: 110px;
  left: -83px;
  border-radius: 0;
  border-color: #C8D0D8;

  > li > a {
    padding: 4px 16px;
    color: $info;
    font-size: 12px;

    .fa, .icon-trash-eqx-icon {
      margin-right: 8px;
      position: relative;
      top: 2px;
      color: $text-color;
      font-size: 16px;
    }

    .icon-trash-eqx-icon {
      font-size: 14px;
    }
  }
}

.arrow-up {
  position: absolute;
  margin: auto;
  top: -3px;
  left: 80px;
  right: 0;
  width: 5px;
  height: 5px;
  background: #fff;
  transform: rotate(-135deg);
  -webkit-transform: rotate(-135deg);
  -moz-transform: rotate(-135deg);
  -o-transform: rotate(-135deg);
  -ms-transform: rotate(-135deg);
  border-right: 1px solid #C8D0D8;
  border-bottom: 1px solid #C8D0D8;
}

.server-dropdown {
	position: absolute;
  right: 12px;
  top: 12px;
}

sp_widget.script:
(function() {
    /* populate the 'data' object */
    /* e.g., data.table = $sp.getValue('table'); */
    data.trackingEnabled = gs.getProperty('EQIX_ANALYTICS_SEGMENT_ENABLED');
    data.categoriesTrackingEnabled = gs.getProperty('EQIX_ANALYTICS_CATEGORIES_ENABLED');
	data.pageTitle = 'Monitoring';
    // Services
	var siCustomerPermission = new EQIX_Customer_Permissions();

    var account = siCustomerPermission.getActiveAccountSysId();
	data.accountOU  = siCustomerPermission.getAccountOuc(account);

    var dashboardOptions = {};
    data.dashboardWidget = $sp.getWidget('msp-monitoring-dashboard', dashboardOptions);

    var alarmsPerDayOptions = {};
    data.alarmsPerDayWidget = $sp.getWidget('msp-alarms-per-day', alarmsPerDayOptions);

    var alarmsHistoryOptions = {
        table: 'u_event_management'
    };
    data.alarmsHistoryWidget = $sp.getWidget('msp-alarms-history-data-table', alarmsHistoryOptions);

    var topTriggersOptions = {
        table: 'u_event_management'
    };
    data.topTriggersWidget = $sp.getWidget('msp-top-10-triggers', topTriggersOptions);

	if (data.accountOU != 'JP' && data.accountOU != 'ES') {
		var maintenanceOptions = {
			table: 'u_mto_maintenance'
		};
		data.maintenanceWidget = $sp.getWidget('msp-maintenance-data-table', maintenanceOptions);
    }


    var model_number = "1-2FDQN8F6"; // - Monitoring 
    var relaxCIPortal = new EQUIX_RelaxCI();
    var result = relaxCIPortal.getServiceManagedAccount(model_number, account);
    data.pemission = result.permission;

	if (result.permission == true) {
        data.managedService = $sp.getWidget('msp-view-product-multiple-cis', {
            "model_number": model_number
        });
        data.createButtonAddComponent = $sp.getWidget('msp-view-button-add-component', {
            "model_number": model_number,
			"href_add_components": "/msp?action=new&autofill=true&u_type=0&u_product_line=e5fd2865dbdadf00448b01a3ca9619ba&u_product_category=85c068a9db5adf00448b01a3ca9619b1&u_product=6b43b0e9dbdadf00448b01a3ca961960&u_service=3478f55c1bd510d08ca477741a4bcb4d"
        });
//gs.addInfoMessage(result.model_number);

        var tableComponentOptions = {
            "table": 'cmdb_ci',
					  "field_list":'u_hostname,ip_address,sys_class_name,location',
            "model_number": result.model_number,
					  "sys_id_ci": result.sys_id_CI
        };

        data.createTableComponent = $sp.getWidget('msp-table-assigned-components',tableComponentOptions);
    }

    /*var reportsOptions = {
    	table: 'task'
    };
    data.reportsWidget = $sp.getWidget('msp-reports-data-table', reportsOptions);*/

})();
